import { useMemo } from "react";
import type { IFuseOptions } from "fuse.js";
import { createSearch, type SearchResult } from "@/lib/search";

/**
 * React hook for fuzzy searching a static dataset.
 * Returns items ranked by relevance with match metadata for highlighting.
 */
export function useFuzzySearch<T>(
  items: readonly T[],
  query: string,
  options: IFuseOptions<T>,
): SearchResult<T>[] {
  const search = useMemo(
    () => createSearch(items, options),
    [items, options],
  );

  return useMemo(() => search(query), [search, query]);
}
